SELECT *, (SELECT COUNT(*) FROM SCM_RJ_SIMP.ALERT_ACCESS_LIST_USER WHERE LIST_ID = SCM_RJ_SIMP.ALERT_ACCESS_LIST.ID) AS USER_COUNT FROM SCM_RJ_SIMP.ALERT_ACCESS_LIST WHERE IS_DELETE = 0
AND NAME LIKE CONCAT('%', #{keyword}, '%')
AND TYPE = #{type}
ORDER BY UPDATE_TIME DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM SCM_RJ_SIMP.ALERT_ACCESS_LIST WHERE IS_DELETE = 0
AND NAME LIKE CONCAT('%', #{keyword}, '%')
AND TYPE = #{type}

SELECT * FROM SCM_RJ_SIMP.ALERT_ACCESS_LIST WHERE IS_DELETE = 0 AND STATUS = 1
AND TYPE = #{type}
ORDER BY NAME ASC

mapper.update:
UPDATE SCM_RJ_SIMP.ALERT_ACCESS_LIST
SET IS_DELETE = 1, UPDATE_TIME = #{updateTime}
WHERE ID = #{id}
